import json
import os
import logging
import traceback
from datetime import datetime, timezone
from enum import Enum
from typing import Any, Optional
from functools import wraps

import boto3
from botocore.exceptions import ClientError

# --- Shared Configuration ---
logger = logging.getLogger()
logger.setLevel(os.environ.get("LOG_LEVEL", "INFO"))

# Environment variables expected on all microservices
SERVICE_NAME = os.environ.get("SERVICE_NAME", "unknown-service")
ENVIRONMENT = os.environ.get("ENVIRONMENT", "dev")
STACK_NAME = os.environ.get("STACK_NAME", "microservices")

# Resource naming convention: {stack_name}-{resource_name}
ORDERS_TABLE = os.environ.get("ORDERS_TABLE", f"{STACK_NAME}-orders")
INVENTORY_TABLE = os.environ.get("INVENTORY_TABLE", f"{STACK_NAME}-inventory")
EVENTS_TOPIC_ARN = os.environ.get("EVENTS_TOPIC_ARN", "")
PROCESSING_QUEUE_URL = os.environ.get("PROCESSING_QUEUE_URL", "")
DATA_BUCKET = os.environ.get("DATA_BUCKET", f"{STACK_NAME}-data")


class ServiceClients:
    """Lazy-initialized shared AWS service clients.
    
    Clients are created once per Lambda container lifecycle (warm start reuse).
    All clients use the shared IAM role automatically via the Lambda execution role.
    """
    _dynamodb = None
    _s3 = None
    _sns = None
    _sqs = None

    @classmethod
    def dynamodb(cls):
        if cls._dynamodb is None:
            cls._dynamodb = boto3.resource("dynamodb")
        return cls._dynamodb

    @classmethod
    def s3(cls):
        if cls._s3 is None:
            cls._s3 = boto3.client("s3")
        return cls._s3

    @classmethod
    def sns(cls):
        if cls._sns is None:
            cls._sns = boto3.client("sns")
        return cls._sns

    @classmethod
    def sqs(cls):
        if cls._sqs is None:
            cls._sqs = boto3.client("sqs")
        return cls._sqs


class EventType(str, Enum):
    ORDER_CREATED = "order.created"
    ORDER_UPDATED = "order.updated"
    ORDER_COMPLETED = "order.completed"
    INVENTORY_UPDATED = "inventory.updated"
    NOTIFICATION_SENT = "notification.sent"
    PROCESSING_FAILED = "processing.failed"


# --- Shared Utilities (used by all microservices) ---

def build_response(status_code: int, body: Any, headers: Optional[dict] = None) -> dict:
    """Standard API Gateway response builder."""
    default_headers = {
        "Content-Type": "application/json",
        "X-Service-Name": SERVICE_NAME,
        "Access-Control-Allow-Origin": "*",
        "Access-Control-Allow-Methods": "GET,POST,PUT,DELETE,OPTIONS",
        "Access-Control-Allow-Headers": "Content-Type,Authorization",
    }
    if headers:
        default_headers.update(headers)

    return {
        "statusCode": status_code,
        "headers": default_headers,
        "body": json.dumps(body, default=str),
    }


def publish_event(event_type: EventType, detail: dict, source: Optional[str] = None):
    """Publish a domain event to the shared SNS topic."""
    if not EVENTS_TOPIC_ARN:
        logger.warning("EVENTS_TOPIC_ARN not configured; skipping event publish.")
        return None

    message = {
        "event_type": event_type.value,
        "source": source or SERVICE_NAME,
        "timestamp": datetime.now(timezone.utc).isoformat(),
        "environment": ENVIRONMENT,
        "detail": detail,
    }

    try:
        response = ServiceClients.sns().publish(
            TopicArn=EVENTS_TOPIC_ARN,
            Message=json.dumps(message, default=str),
            MessageAttributes={
                "event_type": {
                    "DataType": "String",
                    "StringValue": event_type.value,
                },
                "source": {
                    "DataType": "String",
                    "StringValue": source or SERVICE_NAME,
                },
            },
        )
        logger.info(f"Published event {event_type.value}: MessageId={response['MessageId']}")
        return response
    except ClientError as e:
        logger.error(f"Failed to publish event {event_type.value}: {e}")
        raise


def send_to_queue(queue_url: str, message_body: dict, delay_seconds: int = 0,
                  message_group_id: Optional[str] = None):
    """Send a message to an SQS queue."""
    kwargs = {
        "QueueUrl": queue_url,
        "MessageBody": json.dumps(message_body, default=str),
        "DelaySeconds": delay_seconds,
    }
    if message_group_id:
        kwargs["MessageGroupId"] = message_group_id

    try:
        response = ServiceClients.sqs().send_message(**kwargs)
        logger.info(f"Sent message to queue: MessageId={response['MessageId']}")
        return response
    except ClientError as e:
        logger.error(f"Failed to send message to queue {queue_url}: {e}")
        raise


def store_to_s3(key: str, data: Any, bucket: Optional[str] = None,
                content_type: str = "application/json"):
    """Store data to S3."""
    bucket = bucket or DATA_BUCKET
    body = json.dumps(data, default=str) if content_type == "application/json" else data

    try:
        ServiceClients.s3().put_object(
            Bucket=bucket,
            Key=key,
            Body=body if isinstance(body, (bytes, str)) else str(body),
            ContentType=content_type,
        )
        logger.info(f"Stored object s3://{bucket}/{key}")
    except ClientError as e:
        logger.error(f"Failed to store to S3 s3://{bucket}/{key}: {e}")
        raise


def read_from_s3(key: str, bucket: Optional[str] = None) -> Any:
    """Read data from S3."""
    bucket = bucket or DATA_BUCKET
    try:
        response = ServiceClients.s3().get_object(Bucket=bucket, Key=key)
        content = response["Body"].read().decode("utf-8")
        try:
            return json.loads(content)
        except json.JSONDecodeError:
            return content
    except ClientError as e:
        if e.response["Error"]["Code"] == "NoSuchKey":
            logger.warning(f"Object not found: s3://{bucket}/{key}")
            return None
        raise


def lambda_error_handler(func):
    """Decorator for consistent error handling across all Lambda functions."""
    @wraps(func)
    def wrapper(event, context):
        request_id = getattr(context, "aws_request_id", "unknown")
        logger.info(json.dumps({
            "message": "Lambda invocation started",
            "service": SERVICE_NAME,
            "request_id": request_id,
            "function_name": getattr(context, "function_name", "unknown"),
            "event_source": _detect_event_source(event),
        }))

        try:
            result = func(event, context)
            logger.info(json.dumps({
                "message": "Lambda invocation completed",
                "service": SERVICE_NAME,
                "request_id": request_id,
            }))
            return result

        except ClientError as e:
            error_code = e.response["Error"]["Code"]
            error_message = e.response["Error"]["Message"]
            logger.error(json.dumps({
                "message": "AWS service error",
                "service": SERVICE_NAME,
                "request_id": request_id,
                "error_code": error_code,
                "error_message": error_message,
                "traceback": traceback.format_exc(),
            }))

            # Publish failure event for observability
            try:
                publish_event(EventType.PROCESSING_FAILED, {
                    "request_id": request_id,
                    "error_code": error_code,
                    "error_message": error_message,
                })
            except Exception:
                pass

            return build_response(502, {
                "error": "Service dependency error",
                "request_id": request_id,
            })

        except ValueError as e:
            logger.warning(json.dumps({
                "message": "Validation error",
                "service": SERVICE_NAME,
                "request_id": request_id,
                "error": str(e),
            }))
            return build_response(400, {
                "error": str(e),
                "request_id": request_id,
            })

        except Exception as e:
            logger.error(json.dumps({
                "message": "Unhandled exception",
                "service": SERVICE_NAME,
                "request_id": request_id,
                "error": str(e),
                "traceback": traceback.format_exc(),
            }))

            try:
                publish_event(EventType.PROCESSING_FAILED, {
                    "request_id": request_id,
                    "error": str(e),
                })
            except Exception:
                pass

            return build_response(500, {
                "error": "Internal server error",
                "request_id": request_id,
            })

    return wrapper


def _detect_event_source(event: dict) -> str:
    """Detect the source of a Lambda invocation for logging."""
    if "Records" in event:
        first_record = event["Records"][0]
        if "eventSource" in first_record:
            return first_record["eventSource"]
        if "EventSource" in first_record:
            return first_record["EventSource"]
    if "httpMethod" in event or "requestContext" in event:
        return "api-gateway"
    if "source" in event and event.get("detail-type"):
        return "eventbridge"
    if "detail" in event:
        return "scheduled-event"
    return "direct-invocation"


