# EXAMPLE MICROSERVICE: Order Processor Lambda
# This demonstrates how any of the 10+ Lambda functions
# uses the shared role & shared utilities above.
# =========================================================

class OrderService:
    """Order processing business logic."""

    def __init__(self):
        self.table = ServiceClients.dynamodb().Table(ORDERS_TABLE)

    def create_order(self, order_data: dict) -> dict:
        """Create a new order."""
        if not order_data.get("customer_id"):
            raise ValueError("customer_id is required")
        if not order_data.get("items") or not isinstance(order_data["items"], list):
            raise ValueError("items must be a non-empty list")

        now = datetime.now(timezone.utc).isoformat()
        order_id = f"ORD-{datetime.now(timezone.utc).strftime('%Y%m%d%H%M%S')}-{order_data['customer_id'][:8]}"

        total_amount = sum(
            item.get("price", 0) * item.get("quantity", 1)
            for item in order_data["items"]
        )

        order = {
            "order_id": order_id,
            "customer_id": order_data["customer_id"],
            "items": order_data["items"],
            "total_amount": str(total_amount),
            "status": "PENDING",
            "created_at": now,
            "updated_at": now,
        }

        # Store in DynamoDB (uses shared role's DynamoDB permissions)
        self.table.put_item(Item=order)
        logger.info(f"Created order {order_id}")

        # Publish event to SNS (uses shared role's SNS permissions)
        publish_event(EventType.ORDER_CREATED, {
            "order_id": order_id,
            "customer_id": order_data["customer_id"],
            "total_amount": str(total_amount),
        })

        # Send to processing queue (uses shared role's SQS permissions)
        if PROCESSING_QUEUE_URL:
            send_to_queue(PROCESSING_QUEUE_URL, {
                "action": "process_order",
                "order_id": order_id,
            })

        # Archive order data to S3 (uses shared role's S3 permissions)
        store_to_s3(
            key=f"orders/{datetime.now(timezone.utc).strftime('%Y/%m/%d')}/{order_id}.json",
            data=order,
        )

        return order

    def get_order(self, order_id: str) -> Optional[dict]:
        """Retrieve an order by ID."""
        if not order_id:
            raise ValueError("order_id is required")

        response = self.table.get_item(Key={"order_id": order_id})
        item = response.get("Item")
        if not item:
            return None
        return item

    def update_order_status(self, order_id: str, new_status: str) -> dict:
        """Update order status."""
        valid_statuses = {"PENDING", "PROCESSING", "SHIPPED", "DELIVERED", "CANCELLED"}
        if new_status not in valid_statuses:
            raise ValueError(f"Invalid status. Must be one of: {valid_statuses}")

        now = datetime.now(timezone.utc).isoformat()

        response = self.table.update_item(
            Key={"order_id": order_id},
            UpdateExpression="SET #status = :status, updated_at = :updated_at",
            ExpressionAttributeNames={"#status": "status"},
            ExpressionAttributeValues={
                ":status": new_status,
                ":updated_at": now,
            },
            ReturnValues="ALL_NEW",
            ConditionExpression="attribute_exists(order_id)",
        )

        updated_order = response["Attributes"]

        publish_event(EventType.ORDER_UPDATED, {
            "order_id": order_id,
            "new_status": new_status,
        })

        if new_status == "DELIVERED":
            publish_event(EventType.ORDER_COMPLETED, {
                "order_id": order_id,
            })

        return updated_order

    def list_orders_by_customer(self, customer_id: str) -> list:
        """List orders for a customer using a GSI."""
        if not customer_id:
            raise ValueError("customer_id is required")

        response = self.table.query(
            IndexName="customer-index",
            KeyConditionExpression="customer_id = :cid",
            ExpressionAttributeValues={":cid": customer_id},
        )
        return response.get("Items", [])


# --- SQS Event Handler (for queue-triggered invocations) ---

def process_sqs_records(records: list) -> dict:
    """Process SQS messages (e.g., order fulfillment tasks)."""
    order_service = OrderService()
    successes = 0
    failures = []

    for record in records:
        message_id = record.get("messageId", "unknown")
        try:
            body = json.loads(record["body"])

            # Handle SNS-wrapped messages
            if "Message" in body and "TopicArn" in body:
                body = json.loads(body["Message"])

            action = body.get("action")
            logger.info(f"Processing SQS message {message_id}: action={action}")

            if action == "process_order":
                order_id = body["order_id"]
                order_service.update_order_status(order_id, "PROCESSING")
                successes += 1

            elif action == "ship_order":
                order_id = body["order_id"]
                order_service.update_order_status(order_id, "SHIPPED")
                successes += 1

            else:
                logger.warning(f"Unknown action in SQS message {message_id}: {action}")
                successes += 1  # Don't retry unknown actions

        except Exception as e:
            logger.error(f"Failed to process SQS message {message_id}: {e}")
            failures.append({"itemIdentifier": message_id})

    result = {
        "statusCode": 200,
        "body": json.dumps({
            "processed": successes,
            "failed": len(failures),
        }),
    }

    # Partial batch failure reporting
    if failures:
        result["batchItemFailures"] = failures

    return result


# --- SNS Event Handler (for topic-triggered invocations) ---

def process_sns_records(records: list) -> dict:
    """Process SNS notifications (e.g., cross-service events)."""
    for record in records:
        sns_message = record.get("Sns", {})
        message_id = sns_message.get("MessageId", "unknown")

        try:
            message = json.loads(sns_message.get("Message", "{}"))
            event_type = message.get("event_type", "unknown")
            detail = message.get("detail", {})

            logger.info(f"Processing SNS event {event_type}: MessageId={message_id}")

            # React to cross-service events
            if event_type == EventType.ORDER_CREATED.value:
                # Example: Update inventory when order created
                logger.info(f"Order created notification: {detail.get('order_id')}")

            elif event_type == EventType.INVENTORY_UPDATED.value:
                logger.info(f"Inventory updated notification: {detail}")

        except Exception as e:
            logger.error(f"Failed to process SNS message {message_id}: {e}")
            raise  # SNS doesn't support partial batch failures

    return {"statusCode": 200, "body": "SNS records processed"}


# =========================================================
# MAIN LAMBDA HANDLER
# =========================================================

@lambda_error_handler
def handler(event, context):
    """
    Main entry point for the Order Processor Lambda function.
    
    This function handles multiple event sources:
    - API Gateway (REST API calls)
    - SQS (queue-based processing)
    - SNS (event-driven notifications)
    - Direct invocation (internal service calls)
    
    All AWS operations use the SHARED IAM ROLE defined above,
    which grants S3, DynamoDB, SNS, and SQS permissions.
    """
    # --- SQS Event Source ---
    if "Records" in event and event["Records"][0].get("eventSource") == "aws:sqs":
        return process_sqs_records(event["Records"])

    # --- SNS Event Source ---
    if "Records" in event and event["Records"][0].get("EventSource") == "aws:sns":
        return process_sns_records(event["Records"])

    # --- API Gateway Event Source ---
    http_method = event.get("httpMethod", "")
    path = event.get("path", "")
    path_params = event.get("pathParameters") or {}
    query_params = event.get("queryStringParameters") or {}

    order_service = OrderService()

    # POST /orders - Create order
    if http_method == "POST" and path == "/orders":
        body = json.loads(event.get("body", "{}"))
        order = order_service.create_order(body)
        return build_response(201, {
            "message": "Order created successfully",
            "order": order,
        })

    # GET /orders/{order_id} - Get order
    if http_method == "GET" and "order_id" in path_params:
        order_id = path_params["order_id"]
        order = order_service.get_order(order_id)
        if not order:
            return build_response(404, {"error": f"Order {order_id} not found"})
        return build_response(200, {"order": order})

    # GET /orders?customer_id=xxx - List orders by customer
    if http_method == "GET" and path == "/orders" and "customer_id" in query_params:
        customer_id = query_params["customer_id"]
        orders = order_service.list_orders_by_customer(customer_id)
        return build_response(200, {
            "orders": orders,
            "count": len(orders),
        })

    # PUT /orders/{order_id}/status - Update order status
    if http_method == "PUT" and path_params.get("order_id") and "/status" in path:
        order_id = path_params["order_id"]
        body = json.loads(event.get("body", "{}"))
        new_status = body.get("status")
        if not new_status:
            raise ValueError("status is required in request body")
        updated = order_service.update_order_status(order_id, new_status)
        return build_response(200, {
            "message": "Order status updated",
            "order": updated,
        })

    # --- Direct Invocation ---
    if "action" in event:
        action = event["action"]
        if action == "create_order":
            order = order_service.create_order(event.get("order_data", {}))
            return {"success": True, "order": order}
        elif action == "get_order":
            order = order_service.get_order(event.get("order_id", ""))
            return {"success": True, "order": order}
        elif action == "health_check":
            return {
                "success": True,
                "service": SERVICE_NAME,
                "environment": ENVIRONMENT,
                "timestamp": datetime.now(timezone.utc).isoformat(),
            }

    return build_response(400, {"error": "Unsupported request"})